public static int compare(int count, byte[] a, int aOffset, byte[] b, int bOffset) {
    // TODO: dedup this w/ BytesRef.compareTo?
    for(int i=0;i<count;i++) {
      int cmp = (a[aOffset+i]&0xff) - (b[bOffset+i]&0xff);
      if (cmp != 0) {
        return cmp;
      }
    }

    return 0;
  }

